-- Expand both marriage courses from short notes into substantial reading lessons.
-- Keep the existing course UUIDs and slugs because match-gate and rewards depend on them.

UPDATE courses
   SET description = '以凯勒《婚姻的意义》为蓝本的原创导读课程。每单元包含学习目标、正文导读、反思题和讨论题；关键节点需牧者或成熟引荐人确认，完成后获得「已完成婚姻装备」徽章、曝光翻倍与 14 天 VIP 体验。'
 WHERE slug = 'keller-meaning-of-marriage';

UPDATE courses
   SET description = '面向进入匹配池前的基础预备课程。完成八个阅读单元并通过结课考试后，才满足恋爱必修课资格；重点帮助用户理解信仰底线、边界、沟通、家庭财务议题、属灵遮盖、停止关系和正式推进。'
 WHERE slug = 'christian-dating-basics';

WITH expanded_units(course_id, unit_index, title, material, is_pastor_node) AS (
  VALUES
  ('11111111-1111-1111-1111-111111111111'::uuid, 1, '婚姻的秘密：服侍而非自我实现', '学习目标：分辨消费式婚恋和盟约式婚姻的差别，重新整理自己对婚姻的期待。导读：婚姻不是把另一个人变成满足自己的工具，也不是用浪漫感觉证明人生完整。基督徒谈婚姻，首先要问自己是否愿意在基督里学习舍己、服侍、守约和被改变。若一个人只期待婚姻解决孤独、身份焦虑或家庭压力，关系很容易变成索取。福音把人从自我中心里带出来，使爱不只是一种感觉，也是一种在真理中承担责任的行动。反思题：我最希望婚姻替我解决什么问题？这些期待哪些需要被福音校正？讨论题：怎样判断自己是在寻找配偶，还是在寻找一个满足自我的工具？', FALSE),
  ('11111111-1111-1111-1111-111111111111'::uuid, 2, '婚姻的权力：圣灵充满的婚姻', '学习目标：识别亲密关系中的控制、逃避和沉默，学习用福音处理权力。导读：亲密关系越近，越容易暴露人想掌控结果的冲动。有人用强势推进关系，有人用冷淡和消失保护自己，也有人用属灵语言包装自己的要求。圣灵充满的婚姻不是谁压过谁，而是双方都在基督面前降服，愿意听真话、说真话、认错和饶恕。成熟的关系需要界限，也需要温柔；需要表达期待，也需要尊重对方不是自己的附属品。反思题：我在冲突或不安时更容易控制、讨好、逃避，还是沉默？讨论题：一段关系怎样同时保持清楚边界和真实亲近？', FALSE),
  ('11111111-1111-1111-1111-111111111111'::uuid, 3, '婚姻的本质：盟约之爱', '学习目标：理解盟约之爱和合同式关系的不同，并应用到择偶判断。导读：合同式关系常问“对方还能给我什么”，盟约式关系则问“我如何在真理中信实地爱，并帮助对方成为神所喜悦的人”。这不是鼓励盲目承受伤害，而是把承诺、责任和恩典放在感觉之上。进入婚恋关系前，需要诚实看见双方是否愿意在公开、真实、可被提醒的关系中前行。盟约不是冲动承诺，也不是浪漫口号，而是在认识足够真实之后，愿意承担的信实道路。反思题：我对承诺的恐惧或幻想分别是什么？讨论题：什么时候应当继续忍耐沟通，什么时候应当诚实停止关系？', FALSE),
  ('11111111-1111-1111-1111-111111111111'::uuid, 4, '婚姻的使命：彼此成全', '学习目标：从共同使命理解婚姻，而不只从吸引和条件理解婚姻。导读：婚姻的目标不是制造一个没有冲突的安全屋，而是在真实生活中一起更像基督。择偶时当然要看吸引、性格和生活条件，但更要看双方是否愿意被真理校正、被教会群体帮助、一起承担家庭和服事责任。若两个人只会逃避困难，婚姻会放大软弱；若两个人愿意悔改、沟通和服侍，婚姻就能成为成圣的场域。反思题：我希望未来家庭承担怎样的属灵使命和生活责任？讨论题：怎样在认识阶段观察对方是否愿意成长，而不是只看当下条件？', FALSE),
  ('11111111-1111-1111-1111-111111111111'::uuid, 5, '【期中 · 牧者确认】爱你心中的陌生人', '学习目标：承认对方的复杂性，并把关系盲点带入群体见证。导读：越亲近越会发现对方不是自己想象中的完美对象。成熟的爱不是否认差异，也不是急着改造对方，而是在安全、诚实和边界中继续认识。认识关系若已经进入较深阶段，应当开始让牧者、引荐人或成熟肢体知道基本情况，帮助双方看见盲点。牧者节点不是替你决定婚姻，而是保护你不要只被激情、焦虑或孤独驱动。反思题：我最难接纳对方哪一类差异？这背后暴露了我怎样的期待？讨论题：向牧者或引荐人说明关系进展时，哪些事实必须诚实呈现？', TRUE),
  ('11111111-1111-1111-1111-111111111111'::uuid, 6, '拥抱另一个自我：恩典中的悔改', '学习目标：把冲突看作认识自己和操练悔改的机会。导读：亲密关系会照出人的骄傲、惧怕、偶像和防卫模式。恩典不是纵容问题，而是给人勇气承认罪、面对伤害、学习改变。若一个人从不认错，只会把责任推给对方，婚姻会变得危险；若一个人只会自责讨好，也会失去真实沟通。福音让人既不靠表现称义，也不逃避成圣。因此，冲突后的修复能力，比短暂的情绪表现更能显明关系是否成熟。反思题：我在冲突中最常出现的防卫模式是什么？讨论题：怎样区分健康的饶恕、必要的边界和纵容伤害？', FALSE),
  ('11111111-1111-1111-1111-111111111111'::uuid, 7, '单身与婚姻：从永恒看当下', '学习目标：把单身和婚姻都放在神国盼望中，而非身份焦虑中。导读：单身不是低等状态，婚姻也不是终极拯救。基督徒的完整身份在基督里，而不是由婚姻状态决定。正因为如此，预备婚姻的人要先学习在当前处境中忠心、自由和有爱。若一个人把婚姻当作逃离现实的门，婚后仍会把同样的焦虑带进去。健康的婚恋预备包括稳定的教会生活、真实友谊、工作责任、情绪成熟和愿意服事的生命。反思题：我是否把婚姻当作证明自己被爱的凭据？讨论题：单身阶段可以怎样实际操练未来婚姻需要的品格？', FALSE),
  ('11111111-1111-1111-1111-111111111111'::uuid, 8, '性与婚姻：身体的盟约语言', '学习目标：从盟约、尊严和圣洁理解身体与亲密边界。导读：身体不是与信仰无关的私人领域。基督徒理解亲密，需要同时看见创造中的美好、罪带来的扭曲、身体的尊严和婚姻盟约的保护。这不是把身体看低，而是承认身体也在敬拜和委身之中。认识阶段的边界不是压抑爱，而是保护双方不把亲密当作承诺的替代品。若关系靠不断升级的身体亲近维持，很可能掩盖信仰、性格、家庭和责任上的问题。反思题：我对身体、欲望和边界的观念主要从哪里来？讨论题：两个人如何在不羞辱彼此的前提下，清楚约定亲密边界？', FALSE),
  ('11111111-1111-1111-1111-111111111111'::uuid, 9, '婚姻中的友谊与扶持', '学习目标：把配偶理解为属灵朋友，而不仅是浪漫对象。导读：稳固关系需要友谊：能交谈、能同行、能在软弱中扶持，也能在真理中提醒。浪漫会带来吸引，但友谊承载日常。若两个人不能谈论信仰、金钱、家庭、失败、服事和未来，只靠心动很难走远。属灵朋友不是彼此控制，而是彼此认识、彼此代祷、彼此鼓励，也愿意在对方偏离时温柔提醒。反思题：我是否愿意让未来配偶看见真实的我，而不只是我包装过的一面？讨论题：认识阶段有哪些问题能帮助判断两个人是否可能成为属灵朋友？', FALSE),
  ('11111111-1111-1111-1111-111111111111'::uuid, 10, '【结业 · 牧者确认】走向终生的盟约', '学习目标：整合全课，形成进入正式关系或继续分辨的成熟判断。导读：终生盟约不是凭热情硬撑，而是在共同信仰、真实认识、群体见证和持续悔改中前行。完成课程不代表已经准备好结婚，但应当更清楚自己对婚姻的理解、对关系的边界、对教会见证的需要，以及对未来责任的承担。结业节点建议和牧者或引荐人讨论：双方信仰是否真实，家庭与生活议题是否足够清楚，是否存在需要暂停或辅导的问题。反思题：这门课最深地更新了我对婚姻哪一点认识？讨论题：若要进入下一阶段，我需要向对方和属灵遮盖说明哪些具体决定？', TRUE),
  ('22222222-2222-2222-2222-222222222222'::uuid, 1, '为什么先预备，再开始认识', '学习目标：明白预备不是拖延，而是为了减少伤害、提高判断力。导读：认识关系不是逃避孤独的即时满足，而是带着敬畏进入真实沟通。开始前需要确认自己的信仰底线、关系目标、时间节奏和可承担的责任。一个人若还没有基本的教会生活、身份真实性和关系边界，却急着进入亲密，很容易把对方变成情绪出口。预备的重点不是成为完美的人，而是愿意诚实面对自己。预备也包括承认自己仍在学习，不把对方当作辅导员或救世主。反思题：我现在最想从关系中得到什么？讨论题：什么样的预备能保护双方，而不是制造距离？', FALSE),
  ('22222222-2222-2222-2222-222222222222'::uuid, 2, '信仰底线与真实身份', '学习目标：学习在认识初期确认基本信仰与身份真实性。导读：基督徒婚恋不能只看对方是否自称基督徒，还要看是否有真实教会生活、基本信仰告白、可被认识的群体关系和愿意接受提醒的态度。平台资料、信仰档案和引荐人不是形式，而是为了让关系从一开始就在光中。不要急着交换过多隐私，也不要用属灵话术跳过必要核实。真实身份包括姓名、城市、教会背景、婚姻状态、家庭责任和重要限制。反思题：我有哪些信息必须在合适阶段诚实说明？讨论题：确认身份和信任对方之间如何取得平衡？', FALSE),
  ('22222222-2222-2222-2222-222222222222'::uuid, 3, '边界、节奏与安全感', '学习目标：建立认识阶段的沟通频率、隐私和线下见面边界。导读：边界不是不信任，而是给真实关系留下成长空间。认识初期不要过早制造亲密感，不用暧昧试探代替清楚表达，也不要用高频聊天制造虚假的确定感。合宜节奏包括：逐步了解、保留必要隐私、线下见面选择公开安全场景、避免过快绑定情绪。安全感不应靠控制对方回复速度获得，而应来自诚实、稳定和对神的信靠。若一段关系只能靠即时回应维持，就需要重新检查依附和偶像。反思题：我最容易在哪些边界上太快或太慢？讨论题：两个人怎样约定沟通节奏，既真诚又不互相消耗？', FALSE),
  ('22222222-2222-2222-2222-222222222222'::uuid, 4, '如何谈信仰、呼召与教会生活', '学习目标：学习把信仰议题谈具体，而不是停留在标签。导读：信仰不是资料页上的一个选项，而会影响婚姻中的敬拜、教养、服事、金钱、时间和冲突处理。合宜沟通不是第一次聊天就审问对方，而是在关系推进时逐步谈清楚：如何读经祷告，是否稳定聚会，怎样看待教会成员身份，对未来家庭属灵生活有什么期待。真正重要的不是回答多漂亮，而是生命是否真实、是否愿意成长。这类谈话需要谦卑和耐心，不适合用审判口吻压迫对方。反思题：我的信仰生活有哪些真实稳定的部分？讨论题：哪些信仰差异可能影响未来婚姻，需要尽早谈清楚？', FALSE),
  ('22222222-2222-2222-2222-222222222222'::uuid, 5, '家庭、财务、城市与未来责任', '学习目标：识别会真实影响婚姻的生活议题，并学习早期沟通。导读：家庭责任、财务观、职业方向、未来城市、父母期待和生育观都会影响婚姻。很多关系不是因为没有感觉失败，而是因为关键现实议题长期被浪漫遮盖。成熟沟通不是把对方当作面试对象，而是在适当阶段诚实说明自己的责任和限制，也认真听对方的处境。基督徒不应把现实议题看作不属灵，因为信实正是在真实生活中被操练。反思题：我有哪些家庭或财务责任会影响未来关系？讨论题：什么时候适合谈现实议题，怎样谈才不粗暴？', FALSE),
  ('22222222-2222-2222-2222-222222222222'::uuid, 6, '冲突、道歉与停止升级', '学习目标：在小冲突中观察品格，学习不把关系推向失控。导读：认识阶段的冲突很有价值，因为它能显出一个人如何处理失望、边界和被拒绝。成熟的人不一定没有情绪，但愿意解释、倾听、道歉、调整；不成熟的人常用冷暴力、威胁、属灵压迫或消失来保护自己。关系升级前，应当观察双方能否在不同意见中保持尊重。若出现羞辱、控制、撒谎、越界或持续施压，应当暂停推进并寻求帮助。越早学习修复和停止升级，越能保护未来更深的承诺。反思题：我冲突中的第一反应是什么？讨论题：哪些红灯出现时，应当停止升级关系？', FALSE),
  ('22222222-2222-2222-2222-222222222222'::uuid, 7, '属灵遮盖、引荐人与群体见证', '学习目标：理解引荐人和牧者参与不是管控，而是保护与见证。导读：婚恋不是完全私密的两人世界。基督徒关系需要在教会群体中被认识、被祝福、被提醒。引荐人、牧者或成熟肢体不能替你决定婚姻，但可以帮助你看见盲点、核实基本处境、辨认危险信号，也能在关系推进时提供属灵遮盖。若一个人强烈排斥任何可靠第三方知道关系，可能需要谨慎。健康的遮盖让关系更透明，而不是让人失去自由和责任。反思题：我是否愿意让成熟肢体了解我的关系选择？讨论题：向引荐人求助时，应该提供哪些具体信息？', FALSE),
  ('22222222-2222-2222-2222-222222222222'::uuid, 8, '从心动到正式关系，或诚实停止', '学习目标：学习把心动转化为负责任的下一步，也学习体面停止。导读：心动值得珍惜，但不能替代责任。负责任的下一步包括更清楚的关系定义、适当引入属灵遮盖、尊重对方节奏、继续核实关键议题，并愿意在不合适时诚实停止。停止关系不等于失败，暧昧拖延、突然消失、保留备选和羞辱对方才更伤人。基督徒的自由包括可以真诚开始，也可以在真理和爱中结束。清楚比拖延更仁慈，真实比维持表面和平更有爱。反思题：我是否害怕清楚表达关系方向？讨论题：怎样说“不合适”才既真实又尊重对方？', FALSE)
)
INSERT INTO course_units (course_id, unit_index, title, material, is_pastor_node)
SELECT course_id, unit_index, title, material, is_pastor_node
  FROM expanded_units
ON CONFLICT (course_id, unit_index)
DO UPDATE SET
  title = EXCLUDED.title,
  material = EXCLUDED.material,
  is_pastor_node = EXCLUDED.is_pastor_node;
